//! OCEL event-type emission surface for `wasm4pm-compat`.
//!
//! Generated by `wasm4pm-compat-pack` from EventType individuals in the
//! pack ontology. Emission only: ggen emits `OCELEvent` values; discovery,
//! conformance, fitness, and variants belong to `wasm4pm-compat`.

use chrono::{DateTime, FixedOffset};
use wasm4pm_compat::ocel::{OCELEvent, OCELRelationship};

/// Every OCEL event type this generator emits.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum EmittedEventType {
    /// `graph_union_hashed` — binds a `OntologyGraph` object.
    GraphUnionHashed,
    /// `pack_lock_verified` — binds a `Pack` object.
    PackLockVerified,
    /// `receipt_chained` — binds a `SyncReceipt` object.
    ReceiptChained,
}

impl EmittedEventType {
    /// OCEL 2.0 event-type name, as it appears in the log's `eventTypes`.
    pub fn name(self) -> &'static str {
        match self {
            Self::GraphUnionHashed => "graph_union_hashed",
            Self::PackLockVerified => "pack_lock_verified",
            Self::ReceiptChained => "receipt_chained",
        }
    }
}

/// Emit a `graph_union_hashed` event related to one `OntologyGraph` object.
///
/// Caller supplies `time` (no wall-clock reads inside the emission surface).
pub fn emit_graph_union_hashed(
    id: String,
    time: DateTime<FixedOffset>,
    ontology_graph_id: String,
) -> OCELEvent {
    OCELEvent {
        id,
        event_type: "graph_union_hashed".to_string(),
        time,
        attributes: Vec::new(),
        relationships: vec![OCELRelationship {
            object_id: ontology_graph_id,
            qualifier: "OntologyGraph".to_string(),
        }],
    }
}

/// Emit a `pack_lock_verified` event related to one `Pack` object.
///
/// Caller supplies `time` (no wall-clock reads inside the emission surface).
pub fn emit_pack_lock_verified(
    id: String,
    time: DateTime<FixedOffset>,
    pack_id: String,
) -> OCELEvent {
    OCELEvent {
        id,
        event_type: "pack_lock_verified".to_string(),
        time,
        attributes: Vec::new(),
        relationships: vec![OCELRelationship {
            object_id: pack_id,
            qualifier: "Pack".to_string(),
        }],
    }
}

/// Emit a `receipt_chained` event related to one `SyncReceipt` object.
///
/// Caller supplies `time` (no wall-clock reads inside the emission surface).
pub fn emit_receipt_chained(
    id: String,
    time: DateTime<FixedOffset>,
    sync_receipt_id: String,
) -> OCELEvent {
    OCELEvent {
        id,
        event_type: "receipt_chained".to_string(),
        time,
        attributes: Vec::new(),
        relationships: vec![OCELRelationship {
            object_id: sync_receipt_id,
            qualifier: "SyncReceipt".to_string(),
        }],
    }
}
